from collections import defaultdict, deque
h,w=grid.shape
max_comp={}
for color in [3,5,6,7]:
    visited=set()
    maxsize=0
    for r in range(h):
        for c in range(w):
            if grid[r,c]==color and (r,c) not in visited:
                # BFS
                q=[(r,c)]
                visited.add((r,c))
                size=0
                while q:
                    rr,cc=q.pop()
                    size+=1
                    for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                        nr, nc = rr+dr, cc+dc
                        if 0<=nr<h and 0<=nc<w and grid[nr,nc]==color and (nr,nc) not in visited:
                            visited.add((nr,nc))
                            q.append((nr,nc))
                maxsize=max(maxsize,size)
    max_comp[color]=maxsize
max_comp

