def transform(primary):
    h,w=grid.shape
    g=grid.copy()
    # conversion
    conversion=set()
    for r in range(h):
        for c in range(w):
            v=g[r,c]
            if v!=0 and v!=primary:
                for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr,nc=r+dr,c+dc
                    if 0<=nr<h and 0<=nc<w and g[nr,nc]==primary:
                        conversion.add((r,c))
                        break
    g2=g.copy()
    for r,c in conversion:
        g2[r,c]=primary
    for r in range(h):
        for c in range(w):
            if g2[r,c]!=primary:
                g2[r,c]=0
    g3=g2.copy()
    for r in range(h):
        for c in range(w):
            if g2[r,c]==primary:
                neigh=False
                for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                    nr,nc=r+dr,c+dc
                    if 0<=nr<h and 0<=nc<w and g2[nr,nc]==primary:
                        neigh=True; break
                if not neigh:
                    g3[r,c]=0
    return g3
for primary in [3,5,6,7]:
    print("primary",primary)
    out=transform(primary)
    for row in out:
        print(''.join(str(v) if v else '.' for v in row))
    print()

def comp_properties(color):
    # largest component
    h,w=grid.shape
    visited=set()
    best=None
    for r in range(h):
        for c in range(w):
            if grid[r,c]==color and (r,c) not in visited:
                cells=[]
                stack=[(r,c)]
                visited.add((r,c))
                while stack:
                    rr,cc=stack.pop()
                    cells.append((rr,cc))
                    for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
                        nr,nc=rr+dr, cc+dc
                        if 0<=nr<h and 0<=nc<w and grid[nr,nc]==color and (nr,nc) not in visited:
                            visited.add((nr,nc))
                            stack.append((nr,nc))
                if best is None or len(cells)>len(best):
                    best=cells
    if best is None:
        return None
    rs=[r for r,_ in best]; cs=[c for _,c in best]
    return len(best), (min(rs),max(rs),min(cs),max(cs))
for col in [3,5,6,7]:
    print(col, comp_properties(col))

