def adjacent_noise(color):
    cells=[(r,c) for r in range(h) for c in range(w) if grid[r,c]==color]
    noise=0
    for r,c in cells:
        for dr,dc in [(1,0),(-1,0),(0,1),(0,-1)]:
            nr,nc=r+dr,c+dc
            if 0<=nr<h and 0<=nc<w and grid[nr,nc]!=0 and grid[nr,nc]!=color:
                noise+=1
    return noise
for col in [3,5,6,7]:
    print(col, adjacent_noise(col))

