def candidates(grid,c):
    lis=[]
    for i in range(len(grid)-1):
        for j in range(len(grid[0])-1):
            cells=[grid[i][j],grid[i][j+1],grid[i+1][j],grid[i+1][j+1]]
            cnt=cells.count(c)
            if cnt>=3:
                lis.append((i,j,cnt,cells))
    return lis
