def full_candidates(c):
    res=[]
    for (i,j) in cand[c]:
        cells=[rows[i][j],rows[i][j+1],rows[i+1][j],rows[i+1][j+1]]
        if all(v==c for v in cells):
            res.append((i,j))
    return res
